INSERT INTO `post` (`id`, `category_id`, `name`, `name_unsigned`, `description`, `content`, `type`, `avatar`, `banner`, `banner2`, `banner3`, `is_enable`, `is_on_home`, `is_on_menu`, `is_new`, `is_hot`, `tags`, `display_order`, `meta_keyword`, `meta_description`, `view_count`, `is_delete`, `created_at`, `updated_at`, `update_by`) VALUES
(1, NULL, 'Giới thiệu', '', 'Vách ngăn Compact HPL – Nâng tầm không gian, khẳng định đẳng cấp cùng BA MIỀN. Là đơn vị cung cấp và thi công các sản phẩm vách ngăn tiện ích cho trường học, bệnh viện, sân bay, nhà vệ sinh, văn phòng, thành lập được gần 10 năm, đến nay đã xây dựng được lòng tin cho khách hàng bởi dịch vụ chuyên nghiệp, chất lượng vật liệu cao cấp.\r\nChúng tôi luôn nỗ lực phấn đấu giúp khách hàng tìm ra giải pháp thi công tối ưu nhất. Sao cho vẫn đảm bảo công năng, chất lượng của công trình những vẫn phải tiết kiệm chi phí nhất.', '<hr />\r\n<h2><strong>GIỚI THIỆU VỀ C&Ocirc;NG TY TNHH XNK THƯƠNG MẠI BA MIỀN</strong></h2>\r\n\r\n<h3><span style=\"font-size:20px\"><strong>Gi&aacute; trị tạo dựng từ chất lượng &ndash; Uy t&iacute;n khẳng định bằng niềm tin</strong></span></h3>\r\n\r\n<hr />\r\n<p><span style=\"font-size:14px\"><strong>C&ocirc;ng Ty TNHH XNK Thương Mại <span style=\"color:#e74c3c\">BA MIỀN</span></strong> l&agrave; đơn vị chuy&ecirc;n cung cấp v&agrave; thi c&ocirc;ng <strong>v&aacute;ch ngăn vệ sinh Compact HPL, CDF v&agrave; c&aacute;c d&ograve;ng vật tư x&acirc;y dựng ho&agrave;n thiện</strong>, phục vụ đa dạng c&ocirc;ng tr&igrave;nh tr&ecirc;n to&agrave;n quốc: từ văn ph&ograve;ng, nh&agrave; m&aacute;y, trường học đến trung t&acirc;m thương mại, bệnh viện, kh&aacute;ch sạn cao cấp.</span></p>\r\n\r\n<p><span style=\"font-size:14px\">Với gần&nbsp;<strong>[10 năm] kinh nghiệm</strong>, <span style=\"color:#e74c3c\">BA MIỀN</span> đ&atilde; v&agrave; đang trở th&agrave;nh đối t&aacute;c tin cậy của h&agrave;ng trăm nh&agrave; thầu, kiến tr&uacute;c sư v&agrave; chủ đầu tư lớn nhỏ tr&ecirc;n khắp cả nước.</span></p>\r\n\r\n<hr />\r\n<h2><img alt=\"enlightened\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/lightbulb.png\" style=\"height:23px; width:23px\" title=\"enlightened\" /> <strong>Sứ mệnh của ch&uacute;ng t&ocirc;i</strong></h2>\r\n\r\n<p><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span style=\"font-size:12px\">*</span><span style=\"font-size:14px\">Mang đến giải ph&aacute;p tối ưu - Đ&aacute;p ứng mọi nhu cầu về c&ocirc;ng năng, thảm mỹ v&agrave; độ bền cho kh&ocirc;ng gian vệ sinh hiện đại*</span></strong></p>\r\n\r\n<p><span style=\"font-size:14px\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;- Ch&uacute;ng t&ocirc;i kh&ocirc;ng chỉ cung cấp <strong>sản phẩm chất lượng</strong>, m&agrave; c&ograve;n cam kết đồng h&agrave;nh c&ugrave;ng kh&aacute;ch h&agrave;ng trong <strong>tư vấn &ndash; thiết kế &ndash; thi c&ocirc;ng &ndash; bảo tr&igrave;</strong>, tạo n&ecirc;n gi&aacute; trị bền vững v&agrave; l&acirc;u d&agrave;i cho c&ocirc;ng tr&igrave;nh.</span></p>\r\n\r\n<hr />\r\n<h2><span style=\"font-size:20px\"><img alt=\"yes\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/thumbs_up.png\" style=\"height:23px; width:23px\" title=\"yes\" /> <strong>Sản phẩm &amp; Dịch vụ chủ lực</strong></span></h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><strong>V&aacute;ch ngăn vệ sinh Compact HPL</strong>&nbsp;&ndash; Chống nước 100%, bền bỉ, thẩm mỹ cao</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><strong>V&aacute;ch ngăn MFC, PVC, tấm nhựa l&otilde;i đặc</strong></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><strong>Phụ kiện v&aacute;ch ngăn</strong>: Inox 304, nh&ocirc;m định h&igrave;nh, bản lề tự đ&oacute;ng, kh&oacute;a, ch&acirc;n đế,...</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><strong>Thi c&ocirc;ng lắp đặt trọn g&oacute;i</strong> &ndash; Nhanh ch&oacute;ng, chuy&ecirc;n nghiệp</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><strong>Cung cấp vật tư sỉ lẻ to&agrave;n quốc</strong></span></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2><img alt=\"heart\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/heart.png\" style=\"height:23px; width:23px\" title=\"heart\" /> <strong>V&igrave; sao chọn <span style=\"color:#e74c3c\">BA MIỀN</span>?</strong></h2>\r\n\r\n<p><span style=\"font-size:14px\">✅ <strong>Vật tư ch&iacute;nh h&atilde;ng &ndash; Đầy đủ chứng chỉ CO, CQ</strong><br />\r\n✅ <strong>Đội ngũ kỹ thuật l&agrave;nh nghề, nhiều năm kinh nghiệm</strong><br />\r\n✅ <strong>Gi&aacute; cả cạnh tranh &ndash; B&aacute;o gi&aacute; nhanh &ndash; Kh&ocirc;ng ph&aacute;t sinh</strong><br />\r\n✅ <strong>Hỗ trợ khảo s&aacute;t tận nơi &ndash; Giao h&agrave;ng to&agrave;n quốc</strong><br />\r\n✅ <strong>Chế độ bảo h&agrave;nh &ndash; hậu m&atilde;i r&otilde; r&agrave;ng</strong></span></p>\r\n\r\n<hr />\r\n<h2><img alt=\"enlightened\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/lightbulb.png\" style=\"height:23px; width:23px\" title=\"enlightened\" /> <strong>Tầm nh&igrave;n &amp; Định hướng ph&aacute;t triển</strong></h2>\r\n\r\n<p><span style=\"font-size:14px\">Ch&uacute;ng t&ocirc;i hướng tới trở th&agrave;nh một trong những <strong>đơn vị h&agrave;ng đầu trong lĩnh vực v&aacute;ch ngăn vệ sinh tại Việt Nam</strong>, mở rộng thị trường cả về quy m&ocirc; dự &aacute;n lẫn chất lượng dịch vụ, kh&ocirc;ng ngừng đổi mới &ndash; n&acirc;ng cao trải nghiệm kh&aacute;ch h&agrave;ng.</span></p>\r\n\r\n<hr />\r\n<h2><img alt=\"mail\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/envelope.png\" style=\"height:23px; width:23px\" title=\"mail\" /> <strong>Th&ocirc;ng tin li&ecirc;n hệ</strong></h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>C&Ocirc;NG TY TNHH XNK THƯƠNG MẠI BA MIỀN</strong></p>\r\n	</li>\r\n	<li>\r\n	<p><img alt=\"mail\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/envelope.png\" style=\"height:23px; width:23px\" title=\"mail\" /><span style=\"font-size:14px\"> Địa chỉ: Số 256/16D, Đường TX25 - P.Thạnh Xu&acirc;n - Quận 12 - TP.HCM</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">&nbsp; &nbsp; &nbsp; - Xưởng sản xuất HCM: Số 280/112 Ấp 2, x&atilde; Đ&ocirc;ng Thạnh, huyện H&oacute;c M&ocirc;n, TP HCM</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">&nbsp; &nbsp; &nbsp; - Xưởng sản xuất H&agrave; Nội: X&oacute;m 3 Y&ecirc;n Mỹ - Huyện Thanh Tr&igrave; - TP H&agrave; Nội</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><strong>☎&nbsp;Hotline: 0927 680 999 -&nbsp;0983 670 779</strong></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">&nbsp;Website: <a href=\"https://compactbamien.com/\">https://compactbamien.com/</a></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\"><img alt=\"mail\" src=\"https://compactbamien.com/assets/neon/js/ckeditor/plugins/smiley/images/envelope.png\" style=\"height:23px; width:23px\" title=\"mail\" />&nbsp;Email: vachnganbamien.invoice@gmail.com - vachnganbamien@gmail.com</span></p>\r\n	</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', 'about', NULL, '2b960c6be23c7ec311f9dd2246d31fd8_thumb.jpg', NULL, NULL, 1, 1, NULL, NULL, 1, NULL, NULL, 'Giới Thiệu', 'Nội Thất  - Vách Ngăn', NULL, 0, '2020-11-23 21:40:43.000000', '2026-07-10 05:09:40.000000', 'admin'),
(42, 129, 'VÁCH NGĂN COMPACT GIÁ RẺ (thi công hoàn thiện chỉ từ 580k/m2)', 'vach-ngan-compact-gia-re-thi-cong-hoan-thien-chi-tu-580km2', 'Hãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại.\r\n', '<p><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"color:#e67e22\"> &nbsp; <span style=\"font-size:22px\">&nbsp; C&Ocirc;NG TY TNHH XNK THƯƠNG MẠI BA MIỀN&nbsp;</span></span></strong></p>\r\n\r\n<p><strong>H&Atilde;Y T&Igrave;M HIỂU ƯU ĐIỂM TẤM COMPACT HPL MANG LẠI</strong></p>\r\n\r\n<h2><strong>&nbsp; +</strong><strong>&nbsp;<u>V&Aacute;CH NGĂN VỆ SINH</u></strong></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img src=\"/upload/ckfinder/userfiles/images/image(41).png\" style=\"height:376px; width:830px\" /></p>\r\n\r\n<p><img src=\"/upload/ckfinder/userfiles/images/image(1).png\" style=\"height:629px; width:1231px\" /></p>\r\n\r\n<p><img src=\"/upload/ckfinder/userfiles/images/image(2).png\" style=\"height:554px; width:1236px\" /></p>\r\n\r\n<p>#<strong>&nbsp;1 CHỐNG NƯỚC CỰC TỐT&nbsp;</strong></p>\r\n\r\n<p>Tấm Compact&nbsp;l&agrave; một chất liệu c&oacute; thể n&oacute;i n&oacute; sinh ra để l&agrave;m v&aacute;ch ngăn vệ sinh, l&iacute; do l&agrave; v&igrave; nh&agrave; vệ sinh ch&uacute;ng ta c&oacute; thể hiểu l&agrave; nơi sử dụng nước rất nhiều nếu ch&uacute;ng ta sử dụng với chất liệu bị ngấm nước th&igrave; chỉ một thời gian rất ngăn v&aacute;ch ngăn vệ sinh c&oacute; thể phải thay mới v&igrave; kh&ocirc;ng thể sử dụng lại được, với độ chịu nước 100% của tấm compact c&oacute; lẽ sẽ l&agrave; lựa chọn ho&agrave;n hảo nhất để l&agrave;m v&aacute;ch ngăn vệ sinh&nbsp;</p>\r\n\r\n<p>#&nbsp;<strong>2 &Iacute;T PHẢI BẢO TR&Igrave;&nbsp;</strong></p>\r\n\r\n<p>Bởi tấm compact l&agrave; chất liệu chịu nước &amp; chịu nhiệt cực kỳ tốt vậy n&ecirc;n được&nbsp;l&agrave;m rất nhiều ở c&aacute;c nh&agrave; vệ sinh c&ocirc;ng cộng, c&aacute;c ph&ograve;ng tắm c&ocirc;ng cộng vậy n&ecirc;n v&aacute;ch ngăn của ch&uacute;ng ta cần phải đủ mạnh để sử l&yacute; một số lượng lớn người sử dụng trong c&ugrave;ng một l&uacute;c. V&aacute;ch ngăn vệ sinh bằng tấm compact được tạo ra để khắc phục nỗi lo ấy. Bởi phải phục vụ nhiều người như thế kh&ocirc;ng thể ch&aacute;nh t&igrave;nh trạnh v&aacute;ch ngăn vệ sinh bị va đập mạnh v&agrave; rất mạnh nỗi lo ấy tấm compact cũng c&oacute; thể khắc phục được. vậy n&ecirc;n nỗi lo đi bảo h&agrave;nh v&aacute;ch ngăn vệ sinh gần như sẽ kh&ocirc;ng c&oacute; khi bạn sử dụng tấm compact</p>\r\n\r\n<p>#<strong>&nbsp;3 RẤT PHẢI CHĂNG</strong></p>\r\n\r\n<p>D&ugrave; v&aacute;ch ngăn vệ sinh&nbsp;compact kh&ocirc;ng phải l&agrave; loại v&aacute;ch ngăn vệ sinh rẻ nhất m&agrave; bạn c&oacute; thể mua, nhưng ch&uacute;ng cũng kh&ocirc;ng phải l&agrave; loại đắt nhất. V&iacute; dụ, ch&uacute;ng đắt hơn một ch&uacute;t so với nhựa-laminate. Với độ bền đặc biệt của tấm trong m&ocirc;i trường ph&ograve;ng tắm, n&oacute; c&oacute; thể được coi l&agrave; lựa chọn kinh tế nhất về l&acirc;u d&agrave;i. Hơn nữa, v&aacute;ch ngăn c&oacute; nh&ocirc;m định h&igrave;nh giằng b&ecirc;n tr&ecirc;n, phần cứng bằng nh&ocirc;m v&agrave; niox kh&ocirc;ng gỉ chất lượng cao c&agrave;ng l&agrave;m tăng th&ecirc;m gi&aacute; trị.</p>\r\n\r\n<p>#&nbsp;<strong>4 CHỐNG XƯỚC</strong>&nbsp;</p>\r\n\r\n<p>Trong c&aacute;c c&ocirc;ng tr&igrave;nh c&ocirc;ng cộng với tốc độ ph&aacute; hoại cực khoẻ cực kinh khủng th&igrave; việc chống xước lại mang đến một sự ho&agrave;n hảo trong sản phẩm Những kẻ ph&aacute; hoại cố t&igrave;nh c&agrave;o c&aacute;c v&aacute;ch ngăn b&ecirc;n trong nh&agrave; vệ sinh hoặc nh&agrave; tắm, dẫn đến việc mất thẩm mỹ m&agrave; kh&ocirc;ng thể loại bỏ ho&agrave;n to&agrave;n. V&agrave; c&aacute;c v&aacute;ch ngăn bằng tấm compact rất kh&oacute; bị xước hoặc thậm ch&iacute; bị viết l&ecirc;n. Điều đ&oacute; l&agrave;m cho c&aacute;c v&aacute;ch ngăn n&agrave;y tr&ocirc;ng đẹp ngay cả sau nhiều năm sử dụng.</p>\r\n\r\n<p>#&nbsp;<strong>5&nbsp;&nbsp;M&Agrave;U ĐẶC</strong></p>\r\n\r\n<p><strong>Tấm compact</strong>&nbsp;c&oacute; rất nhiều m&agrave;u sắc để cho qu&yacute; kh&aacute;ch c&oacute; thể lựa chọn v&agrave; ph&ugrave; hợp với m&ocirc;i trường l&agrave;m việc của mọi người cung cấp một m&ocirc;i trường y&ecirc;n tĩnh v&agrave; trung lập, bất kể bạn chọn m&agrave;u n&agrave;o&nbsp;<strong>tấm compact</strong>&nbsp;đều c&oacute; thể đ&aacute;p ứng được nhu cầu của qu&yacute; kh&aacute;ch, đảm bảo rằng v&aacute;ch ngăn vệ sinh sẽ l&agrave; lựa chọn ho&agrave;n hảo để qu&yacute; kh&aacute;ch lựa chọn v&agrave; tin tưởng&nbsp;</p>\r\n\r\n<p>#<strong>&nbsp;6&nbsp;ĐA NĂNG</strong></p>\r\n\r\n<p>Tại sao n&oacute;i v&aacute;ch ngăn vệ sinh bằng tấm compact lại đa năng đến thế vi những l&yacute; do chất lượng cực kỳ tốt ch&ocirc;ng nước , chịu nhiệt độ cao , ch&ocirc;ng xước...v&agrave; c&oacute; m&agrave;u xắc đa dạng tuỳ từng m&agrave;u m&agrave; ch&uacute;ng ta c&oacute; thể sử dụng cho trường học , nh&agrave; h&agrave;ng sang trọng, c&aacute;c qu&aacute;n c&agrave; ph&ecirc;,...</p>\r\n\r\n<p># HO&Agrave;N TO&Agrave;N H&Agrave;I L&Ograve;NG VỚI V&Aacute;CH NGĂN NH&Agrave; VỆ SINH BẰNG&nbsp;<strong>TẤM COMPACT</strong></p>\r\n\r\n<p><strong>7. LI&Ecirc;N HỆ ĐẶT H&Agrave;NG V&Agrave; THI C&Ocirc;NG TRỌN G&Oacute;I</strong></p>\r\n\r\n<p>* Để được tư vấn v&agrave; hỗ trợ giải đ&aacute;p mọi thắc mắc qu&yacute; kh&aacute;ch h&agrave;ng xin vui l&ograve;ng li&ecirc;n hệ hotline của c&ocirc;ng ty:</p>\r\n\r\n<p><span style=\"color:#e74c3c\">Hotline:&nbsp;0927.680.999 (Mr. Tuyến)</span></p>\r\n\r\n<p><span style=\"color:#e74c3c\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;0909.256.236 (Mr. Ph&aacute;t)</span></p>\r\n\r\n<p><span style=\"color:#e74c3c\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;0909.224.979 (Mr&nbsp;Khoa)</span></p>\r\n\r\n<p><span style=\"color:#e74c3c\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;0983.670.779&nbsp;(Mr. Tuy&ecirc;n)</span></p>\r\n\r\n<p><strong>Wedsite</strong>:&nbsp;&nbsp;<a href=\"https://compactbamien.com/\">compactbamien.com</a></p>\r\n\r\n<p><strong>Wedsite</strong>:&nbsp;&nbsp;<a href=\"https://vachnganbamien.com/\">vachnganbamien.com</a></p>\r\n\r\n<p><strong>Wedsite</strong>:&nbsp;&nbsp;<a href=\"https://tongkhotamcompact.vn/\">tongkhotamcompact.vn</a></p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<a href=\"https://vachnganbamien.com/bao-gia/bao-gia-thi-cong-vach-ngan-compact-hpl-nam-2024\">B&Aacute;O GI&Aacute; THI C&Ocirc;NG V&Aacute;CH NGĂN Compact HPL (năm 2024) (</a><a href=\"https://compactbamien.com/\">compactbamien.com</a><a href=\"https://vachnganbamien.com/bao-gia/bao-gia-thi-cong-vach-ngan-compact-hpl-nam-2024\">)</a></p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Gmail:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;vachnganbamien.invoice@gmail.com - vachnganbamien@gmail.com</p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', 'quotation', '5126256df04589ff9c4a3cf578df3cb3_thumb.jpg', NULL, NULL, NULL, 1, 1, NULL, NULL, 0, 'vách ngăn, vệ sinh, di động, compact, thi công, công trình, báo giá', 4, 'Bảng giá tham khảo', 'Bảng giá tham khảo', 127, 0, '2020-12-05 06:19:59.000000', '2026-06-27 07:59:47.000000', 'admin'),
