(129, 'Báo Giá', 'bao-gia', 'Cam kết Về Chất lượng Tốt Nhất </br> \r\n►Chứng chỉ CO , CQ  </br> \r\n►Màu sắc đa dạng </br>\r\n►Thi công chuẩn mẫu theo Hợp Đồng</br>', NULL, 0, 0, 'post', 'e355876318d3d18d88c2_(1)1.jpg', 'e355876318d3d18d88c2_(1)1_cropped_thumb.jpg', 1, 1, 1, 1, 'báo giá', 'Báo giá các loại vách ngăn và phụ kiện', 0, '2021-10-15 06:49:54.000000', '2022-09-30 07:25:30.000000', 'sa'),
(130, 'Tin Tức', 'tin-tuc', '► Tin tức nổi bật, chúng tôi luôn cập nhật tin tức thị trường theo một cách nhanh nhất</br> \r\n►Cách thi công vách ngăn vệ sinh  </br> \r\n►Cách lựa chọn</br>\r\n►Tin Tức chuyên ngành</br>', NULL, 0, 0, 'post', 'vách-ngăn-vệ-sinh-compact-hpl-13.png', 'vách-ngăn-vệ-sinh-compact-hpl-13_cropped_thumb.png', 1, 1, 1, 2, 'Tin Tức', 'Tin tức mới nhất về các loại vách ngăn và phụ kiện', 0, '2021-10-15 06:50:15.000000', '2022-09-30 07:25:55.000000', 'sa');
