(148, 125, 'Công Trình Tại Tây Ninh', 'cong-trinh-tai-tay-ninh', 'Thi Công 155m2 - Tấm Màu Ghi ', '<h3>➡️&nbsp;<strong>ƯU ĐIỂM NỔI BẬT CỦA TẤM COMPACT HPL:</strong></h3>\r\n\r\n<p>✅ <strong>Chống nước 100%</strong> &ndash; kh&ocirc;ng phồng rộp, cong v&ecirc;nh hay ẩm mốc trong m&ocirc;i trường ẩm ướt.<br />\r\n<br />\r\n✅ <strong>Bề mặt chống trầy, dễ lau ch&ugrave;i</strong>, lu&ocirc;n s&aacute;ng b&oacute;ng &amp; sạch đẹp.<br />\r\n<br />\r\n✅ <strong>Chịu va đập &ndash; chịu nhiệt tốt</strong>, bền đẹp hơn gỗ <em>c&ocirc;</em>ng nghiệp th&ocirc;ng thường.<br />\r\n<br />\r\n✅ <strong>Kh&ocirc;ng bắt lửa &ndash; chống ch&aacute;y nhẹ</strong>, an to&agrave;n cho <em>c&ocirc;</em>ng tr&igrave;nh <em>c&ocirc;</em>ng cộng.<br />\r\n<br />\r\n✅ <strong>Tuổi thọ l&ecirc;n đến 20 năm</strong>, tiết kiệm chi ph&iacute; bảo tr&igrave;, thay thế.<br />\r\n<br />\r\n✅ <strong>Đa dạng m&agrave;u sắc, độ d&agrave;y &amp; k&iacute;ch thước</strong>, dễ d&agrave;ng phối m&agrave;u &ndash; tạo phong c&aacute;ch ri&ecirc;ng cho từng kh&ocirc;ng gian.<br />\r\n<br />\r\n✅ <strong>Th&acirc;n thiện m&ocirc;i trường</strong>, kh&ocirc;ng chứa formaldehyde độc hại.</p>\r\n\r\n<hr />\r\n<p>➡️&nbsp;<strong>Ứng dụng phổ biến:</strong><br />\r\n<br />\r\n➡️&nbsp;V&aacute;ch ngăn vệ sinh, v&aacute;ch văn ph&ograve;ng<br />\r\n<br />\r\n➡️ Mặt b&agrave;n th&iacute; nghiệm, b&agrave;n học, b&agrave;n l&agrave;m việc<br />\r\n<br />\r\n➡️&nbsp; Tủ locker, tủ bếp, ốp tường trang tr&iacute;</p>\r\n', 570000, 0, 'product', 'f88701632b9207e872311abfd9303851.jpg', 'f88701632b9207e872311abfd9303851_thumb.jpg', 1, 1, 1, 1, 1, 1, 2, 0, 0, 'Vách ngăn vệ sinh màu 1006', 'vách màu ghi 1006', 69, 0, '2021-10-25 02:36:47.000000', '2026-07-10 03:42:26.000000', 'admin'),
(159, 125, 'Công Trình Đồng Nai', 'cong-trinh-dong-nai', 'Thi Công 187m2 - Tấm Màu Vân Gỗ ', '<p>➡️ ƯU ĐIỂM NỔI BẬT CỦA TẤM COMPACT HPL:<br />\r\n✅ Chống nước 100% &ndash; kh&ocirc;ng phồng rộp, cong v&ecirc;nh hay ẩm mốc trong m&ocirc;i trường ẩm ướt.</p>\r\n\r\n<p>✅ Bề mặt chống trầy, dễ lau ch&ugrave;i, lu&ocirc;n s&aacute;ng b&oacute;ng &amp; sạch đẹp.</p>\r\n\r\n<p>✅ Chịu va đập &ndash; chịu nhiệt tốt, bền đẹp hơn gỗ c&ocirc;ng nghiệp th&ocirc;ng thường.</p>\r\n\r\n<p>✅ Kh&ocirc;ng bắt lửa &ndash; chống ch&aacute;y nhẹ, an to&agrave;n cho c&ocirc;ng tr&igrave;nh c&ocirc;ng cộng.</p>\r\n\r\n<p>✅ Tuổi thọ l&ecirc;n đến 20 năm, tiết kiệm chi ph&iacute; bảo tr&igrave;, thay thế.</p>\r\n\r\n<p>✅ Đa dạng m&agrave;u sắc, độ d&agrave;y &amp; k&iacute;ch thước, dễ d&agrave;ng phối m&agrave;u &ndash; tạo phong c&aacute;ch ri&ecirc;ng cho từng kh&ocirc;ng gian.</p>\r\n\r\n<p>✅ Th&acirc;n thiện m&ocirc;i trường, kh&ocirc;ng chứa formaldehyde độc hại.</p>\r\n\r\n<p>➡️ Ứng dụng phổ biến:</p>\r\n\r\n<p>➡️ V&aacute;ch ngăn vệ sinh, v&aacute;ch văn ph&ograve;ng</p>\r\n\r\n<p>➡️ Mặt b&agrave;n th&iacute; nghiệm, b&agrave;n học, b&agrave;n l&agrave;m việc</p>\r\n\r\n<p>➡️ &nbsp;Tủ locker, tủ bếp, ốp tường trang tr&iacute;</p>\r\n', 640000, 0, 'product', 'c5be1b9ee369b4bddfa671cf02cc4fa4.jpg', 'c5be1b9ee369b4bddfa671cf02cc4fa4_thumb.jpg', 1, 1, 1, 1, 1, 1, 4, 0, 0, 'Vách ngăn vệ sinh vân gỗ', 'Vách ngăn vệ sinh màu 3612', 69, 0, '2021-10-25 03:25:45.000000', '2026-07-11 05:50:07.000000', 'admin'),
(160, 125, 'Công Trình Gò Vấp', 'cong-trinh-go-vap', 'Thi Công 357m2 - Tấm Màu Xanh Lá - Mã 1022', '<p>➡️ ƯU ĐIỂM NỔI BẬT CỦA TẤM COMPACT HPL:<br />\r\n✅ Chống nước 100% &ndash; kh&ocirc;ng phồng rộp, cong v&ecirc;nh hay ẩm mốc trong m&ocirc;i trường ẩm ướt.</p>\r\n\r\n<p>✅ Bề mặt chống trầy, dễ lau ch&ugrave;i, lu&ocirc;n s&aacute;ng b&oacute;ng &amp; sạch đẹp.</p>\r\n\r\n<p>✅ Chịu va đập &ndash; chịu nhiệt tốt, bền đẹp hơn gỗ c&ocirc;ng nghiệp th&ocirc;ng thường.</p>\r\n\r\n<p>✅ Kh&ocirc;ng bắt lửa &ndash; chống ch&aacute;y nhẹ, an to&agrave;n cho c&ocirc;ng tr&igrave;nh c&ocirc;ng cộng.</p>\r\n\r\n<p>✅ Tuổi thọ l&ecirc;n đến 20 năm, tiết kiệm chi ph&iacute; bảo tr&igrave;, thay thế.</p>\r\n\r\n<p>✅ Đa dạng m&agrave;u sắc, độ d&agrave;y &amp; k&iacute;ch thước, dễ d&agrave;ng phối m&agrave;u &ndash; tạo phong c&aacute;ch ri&ecirc;ng cho từng kh&ocirc;ng gian.</p>\r\n\r\n<p>✅ Th&acirc;n thiện m&ocirc;i trường, kh&ocirc;ng chứa formaldehyde độc hại.</p>\r\n\r\n<p>➡️ Ứng dụng phổ biến:</p>\r\n\r\n<p>➡️ V&aacute;ch ngăn vệ sinh, v&aacute;ch văn ph&ograve;ng</p>\r\n\r\n<p>➡️ Mặt b&agrave;n th&iacute; nghiệm, b&agrave;n học, b&agrave;n l&agrave;m việc</p>\r\n\r\n<p>➡️ &nbsp;Tủ locker, tủ bếp, ốp tường trang tr&iacute;</p>\r\n', 620000, 0, 'product', '7418dfab0424151888d6a748578f8988.jpg', '7418dfab0424151888d6a748578f8988_thumb.jpg', 1, 1, 1, 1, 1, 1, 3, 0, 0, 'Vách ngăn vệ sinh mã 3075', 'Vách ngăn vệ sinh mã 3057', 69, 0, '2021-10-25 03:34:50.000000', '2026-07-10 03:43:01.000000', 'admin'),
(161, 110, 'Công Trình Quận 2', 'cong-trinh-quan-2', 'Thi Công 360m2 - Tấm Màu Xanh Dương', '<p>➡️ ƯU ĐIỂM NỔI BẬT CỦA TẤM COMPACT HPL:<br />\r\n✅ Chống nước 100% &ndash; kh&ocirc;ng phồng rộp, cong v&ecirc;nh hay ẩm mốc trong m&ocirc;i trường ẩm ướt.</p>\r\n\r\n<p>✅ Bề mặt chống trầy, dễ lau ch&ugrave;i, lu&ocirc;n s&aacute;ng b&oacute;ng &amp; sạch đẹp.</p>\r\n\r\n<p>✅ Chịu va đập &ndash; chịu nhiệt tốt, bền đẹp hơn gỗ c&ocirc;ng nghiệp th&ocirc;ng thường.</p>\r\n\r\n<p>✅ Kh&ocirc;ng bắt lửa &ndash; chống ch&aacute;y nhẹ, an to&agrave;n cho c&ocirc;ng tr&igrave;nh c&ocirc;ng cộng.</p>\r\n\r\n<p>✅ Tuổi thọ l&ecirc;n đến 20 năm, tiết kiệm chi ph&iacute; bảo tr&igrave;, thay thế.</p>\r\n\r\n<p>✅ Đa dạng m&agrave;u sắc, độ d&agrave;y &amp; k&iacute;ch thước, dễ d&agrave;ng phối m&agrave;u &ndash; tạo phong c&aacute;ch ri&ecirc;ng cho từng kh&ocirc;ng gian.</p>\r\n\r\n<p>✅ Th&acirc;n thiện m&ocirc;i trường, kh&ocirc;ng chứa formaldehyde độc hại.</p>\r\n\r\n<p>➡️ Ứng dụng phổ biến:</p>\r\n\r\n<p>➡️ V&aacute;ch ngăn vệ sinh, v&aacute;ch văn ph&ograve;ng</p>\r\n\r\n<p>➡️ Mặt b&agrave;n th&iacute; nghiệm, b&agrave;n học, b&agrave;n l&agrave;m việc</p>\r\n\r\n<p>➡️ &nbsp;Tủ locker, tủ bếp, ốp tường trang tr&iacute;</p>\r\n', 650000, 0, 'product', '7a5e8f801a7e2c1b6648e94967a07cad.jpg', '7a5e8f801a7e2c1b6648e94967a07cad_thumb.jpg', 1, 1, 1, 1, 1, 1, 5, 0, 0, 'Vách ngăn vệ sinh mã 3001', 'Vách ngăn vệ sinh mã 3001', 69, 0, '2021-10-25 03:40:13.000000', '2025-11-05 09:12:54.000000', 'admin'),
